// Comparar listas e identificar alunos inativos
const activeStudents = $input.first().json;
const allStudents = $input.last().json;

// Criar map dos alunos ativos por celular
const activeMap = new Map();
activeStudents.forEach(student => {
  const celular = (student.celular || student.telefone || '').toString().replace(/\D/g, '');
  if (celular) {
    activeMap.set(celular, student);
  }
});

// Identificar inativos
const inactiveStudents = [];
allStudents.forEach(student => {
  const celular = (student.celular || student.telefone || '').toString().replace(/\D/g, '');
  if (celular && !activeMap.has(celular)) {

    // Classificação por segmento
    let segmento = 'FRIO';
    let prioridade = 4;
    let diasEstimadosInativo = Math.floor(Math.random() * 120); // Simulação

    if (diasEstimadosInativo <= 30) {
      segmento = 'QUENTE';
      prioridade = 1;
    } else if (diasEstimadosInativo <= 60) {
      segmento = 'MORNO';
      prioridade = 2;
    } else if (diasEstimadosInativo <= 90) {
      segmento = 'FRIO';
      prioridade = 3;
    } else {
      segmento = 'CONGELADO';
      prioridade = 4;
    }

    // Formatar WhatsApp
    let whatsapp = celular;
    if (whatsapp.length === 9) {
      whatsapp = '5565' + whatsapp;
    } else if (whatsapp.length === 11 && whatsapp.startsWith('65')) {
      whatsapp = '55' + whatsapp;
    }

    inactiveStudents.push({
      nome_completo: student.nome_completo || student.nome || '',
      primeiro_nome: (student.nome_completo || student.nome || '').split(' ')[0],
      celular: celular,
      whatsapp: whatsapp,
      email: student.email || '',
      idade: student.idade || 0,
      sexo: student.sexo || '',
      segmento: segmento,
      prioridade: prioridade,
      dias_inativo_estimado: diasEstimadosInativo,
      potencial_reativacao: segmento === 'QUENTE' ? 'ALTO' : segmento === 'MORNO' ? 'MEDIO' : 'BAIXO'
    });
  }
});

// Ordenar por prioridade
inactiveStudents.sort((a, b) => a.prioridade - b.prioridade);

console.log(`Encontrados ${inactiveStudents.length} alunos inativos`);
console.log(`QUENTE: ${inactiveStudents.filter(s => s.segmento === 'QUENTE').length}`);
console.log(`MORNO: ${inactiveStudents.filter(s => s.segmento === 'MORNO').length}`);
console.log(`FRIO: ${inactiveStudents.filter(s => s.segmento === 'FRIO').length}`);
console.log(`CONGELADO: ${inactiveStudents.filter(s => s.segmento === 'CONGELADO').length}`);

return inactiveStudents.map(student => ({ json: student }));

// Gerar relatório de segmentação
const students = $input.all();

const summary = {
  total_inativos: students.length,
  por_segmento: {
    QUENTE: students.filter(s => s.json.segmento === 'QUENTE').length,
    MORNO: students.filter(s => s.json.segmento === 'MORNO').length,
    FRIO: students.filter(s => s.json.segmento === 'FRIO').length,
    CONGELADO: students.filter(s => s.json.segmento === 'CONGELADO').length
  },
  potencial_reativacao: {
    ALTO: students.filter(s => s.json.potencial_reativacao === 'ALTO').length,
    MEDIO: students.filter(s => s.json.potencial_reativacao === 'MEDIO').length,
    BAIXO: students.filter(s => s.json.potencial_reativacao === 'BAIXO').length
  },
  estimativa_receita: {
    mensal_potencial: students.filter(s => s.json.segmento === 'QUENTE').length * 129, // R$ 129 mensalidade
    meta_reativacao_30pct: Math.floor(students.length * 0.3) * 129
  },
  data_segmentacao: new Date().toISOString(),
  academia: 'Full Force Academia - Matupá-MT'
};

return { json: summary };
